SellPreciousTipConfig = {}
SellPreciousTipConfig.precious = {}

function SellPreciousTipConfig:initConfig(config)
    self:initSellPreciousConfig(config)
end

function SellPreciousTipConfig:initSellPreciousConfig(config)
    for i, v in pairs(config) do
        local item = {}
        item.Id = tonumber(v.Id)
        item.ItemId = tonumber(v.ItemId)
        item.ItemMeta = tonumber(v.ItemMeta)
        self.precious[v.Id] = item
    end
end

function SellPreciousTipConfig:checkIfCanPrecious(itemId, itemMeta)
    for i, k in pairs(self.precious) do
        if k.ItemMeta == -1 then
            if k.ItemId == itemId then
                return true
            end
        else
            if k.ItemId == itemId and k.ItemMeta == itemMeta then
                return true
            end
        end
    end
    return false
end

function SellPreciousTipConfig:isSpItemMeta(itemId)
    for i, k in pairs(self.precious) do
        if itemId == k.ItemId then
            if k.itemMeta == -1 then
                return true
            end
        end
    end
    return false
end





return SellPreciousTipConfig